let type = flow.get('product_type');
let quantite = flow.get('nb_product');
let rawPriority = flow.get('priority');

let priority = (rawPriority === true || rawPriority === "true" || rawPriority === 1) ? 1 : 0;

if (!type || !quantite) {
    node.warn("Incomplete input");
    return null;
}

msg.topic = "INSERT INTO Orders (nb_product, product_type, status, priority) VALUES (?, ?, 'WAITING', ?);";
msg.payload = [quantite, type, priority];

flow.set('priority', false);

return msg;

msg.topic = `
    SELECT COUNT(*) as total_active FROM Production WHERE status = 'IN_PROGRESS';
`;
return msg;

let sn = msg.sn;
let order_id = msg.order_id;
let cart_id = msg.cart_id; 

msg.topic = "INSERT INTO Production (productSN, order_id, cart_id, current_station, status) VALUES (?, ?, ?, 'Station1', 'IN_PROGRESS');";

msg.payload = [sn, order_id, cart_id];

return msg;

let fleet = global.get('factory_fleet');
let stations = global.get('factory_stations'); 
let priorityType = global.get('production_priority');
let data = msg.productData;

let order_id = msg.order_id;
let remainingProducts = msg.remainingProducts;

if (remainingProducts > 0) {
    if (stations[1] !== null) {
        node.warn(`BLOCKED : Station 1 occupied by cart : ${stations[1]}`);
        return null; 
    }

    let freeCart = fleet.find(c => c.sn === null);
    if (!freeCart) {
        node.warn("No free carts available");
        return null;
    }

    let sn = order_id + "_" + Date.now();

    freeCart.sn = sn;
    freeCart.state = 'UPDATE';
    freeCart.currentStation = 1;
    freeCart.productData = data;
    freeCart.isBypassed = false;
    freeCart.order_id = order_id; 

    global.set('factory_fleet', fleet);

    msg.sn = sn;
    msg.order_id = order_id;

    msg.cart_id = freeCart.cart_id; 

    node.warn(`Cart ${freeCart.cart_id} processing to Station 1`);
    msg.machineCommand = { action: 'DECISION', sn: sn };

    return msg;
} else {
    node.warn("No Order Processing");
    return null;
}

let fleet = global.get('factory_fleet');
let stations = global.get('factory_stations');

let sn = msg.payload.sn || msg.sn;
let cart = fleet.find(c => c.sn === sn);

if (!cart) return null;
if (cart.state !== 'UPDATE') return null;

let numStation = cart.currentStation;

if (numStation > 6) {
    msg.topic = "UPDATE Production SET status = 'FINISHED', current_station = 'OUT' WHERE productSN = ?;";
    msg.payload = [sn];
    msg.order_id = cart.order_id;
    msg.productSN = sn;

    stations[6] = null;

    let cartId = cart.cart_id; 
    cart.sn = null;
    cart.order_id = null;
    cart.productData = null;
    cart.currentStation = 0;
    cart.state = 'IDLE';
    cart.isBypassed = false;

    global.set('factory_fleet', fleet);
    global.set('factory_stations', stations);

    return [msg, { payload: `[Product ${sn}] Production finished ! Cart ${cartId} is now FREE.` }];
}

stations[numStation] = cart.cart_id;
if (numStation > 1) {
    stations[numStation - 1] = null;
}

let dbUpdateMsg = {
    topic: "UPDATE Production SET current_station = ? WHERE productSN = ?;",
    payload: ["Station" + numStation, sn],
    order_id: cart.order_id,
    productSN: sn
};

let commandMsg = { payload: {} };
let stopCol = "Station" + numStation + "Stop";
let opCol = "Station" + numStation + "Op";

cart.state = 'CART_IN_WAIT';


commandMsg.payload = `[Cart ${cart.cart_id} | Product ${sn} -> Station ${numStation}]. Waiting for CART_IN`;


global.set('factory_fleet', fleet);
global.set('factory_stations', stations);

return [dbUpdateMsg, commandMsg];

let machineAnswer = msg.payload; 
let station_number = machineAnswer.station

let fleet = global.get('factory_fleet');
let stations = global.get('factory_stations'); 

if (!fleet || !stations) return null;  

let cart_id = stations[station_number];

// if (cartId !== undefined) {
// } else {
// }

let cart = fleet.find(c => c.cart_id === cart_id);

if (!cart || cart.state === 'IDLE') return null;

let sn = cart.sn;

let nextStation = cart.currentStation + 1;
let stopCol = "Station" + cart.currentStation + "Stop";
let opCol = "Station" + cart.currentStation + "Op";

if (machineAnswer.response === "CART_IN" && cart.state === 'CART_IN_WAIT') {

    if (cart.productData[stopCol] === 1 || cart.productData[stopCol] === true) {
        cart.state = 'DONE_WAIT';
        global.set('factory_fleet', fleet);
        return [
            { payload: `[Station  ${cart.currentStation} | Cart ${cart.cart_id}] CART_IN received. Send instruction : ${cart.productData[opCol]}` },
            { payload: { action: 'CHECK_NEXT_PRODUCT' }, order_id: cart.order_id }
        ];    
    } else {
        if (stations[nextStation] === null || nextStation > 6) {
            cart.state = 'UPDATE';
            let ancientStation = cart.currentStation;
            cart.currentStation++;

            global.set('factory_fleet', fleet);



            return [
                { payload: `[Station  ${ancientStation} | Cart ${cart.cart_id}] CART_IN received. No instruction : BYPASSING... Release cart` },
                { payload: { action: 'DECISION', sn: sn } }
            ];
        } else {
            cart.state = 'BLOCKED';
            global.set('factory_fleet', fleet);
            return [ { payload: `[Station  ${cart.currentStation} | Cart ${cart.cart_id}] Operation BYPASSED but PATH BLOCKED at Station ${nextStation}. Waiting...` }, 
                        { 
                            payload: { action: 'CHECK_NEXT_PRODUCT' }, 
                            order_id: cart.order_id
                        }
        ];
        }
    }
}

if (machineAnswer.response === "DONE" && cart.state === 'DONE_WAIT') {

    if (stations[nextStation] === null || nextStation > 6) {
        cart.state = 'UPDATE';
        let ancientStation = cart.currentStation;
        cart.currentStation++;

        global.set('factory_fleet', fleet);

        return [
            { 
                payload: `[Station  ${ancientStation} | Cart ${cart.cart_id}] DONE received. Release cart for station ${cart.currentStation} !` ,
                sn: sn
            }, 
            { payload: { action: 'DECISION', sn: sn } } 
        ];

    } else {
        cart.state = 'BLOCKED';
        global.set('factory_fleet', fleet);
        return [ { payload: `[Cart ${cart.cart_id}] DONE received but PATH BLOCKED at Station ${nextStation}. Waiting...` }, 
                { 
                    payload: { action: 'CHECK_NEXT_PRODUCT' }, 
                    order_id: cart.order_id
                }
        ];
    }
}

if (cart.state === 'BLOCKED') {
    if (stations[nextStation] === null || nextStation > 6) {

        cart.state = 'UPDATE';

        let ancientStation = cart.currentStation;
        cart.currentStation++;

        global.set('factory_fleet', fleet);

        return [
            {
                payload: `[Station  ${ancientStation} | Cart ${cart.cart_id}] PATH CLEARED for Station ${cart.currentStation}. MOVE CART !`,
                sn: sn
            },
            { payload: { action: 'DECISION', sn: sn } }
        ];

    } else {
        return [{ payload: `[Cart ${cart.cart_id}] Still BLOCKED. Waiting for Station ${nextStation} to clear...` }, 
    { 
        payload: { action: 'CHECK_NEXT_PRODUCT' }, 
        order_id: cart.order_id
    }
        ];
    }


}

return null;

if (!Array.isArray(msg.payload)) {
    return null;
}

msg.options = msg.payload.map(row => row.product_type);

msg.payload = "";

return msg;

if (msg.orderIndex === undefined) {
    if (!msg.payload || msg.payload.length === 0) {
        node.status({ fill: "grey", shape: "ring", text: "Aucune commande" });
        return null;
    }
    msg.ordersArray = msg.payload; 
    msg.orderIndex = 0;           
}

if (msg.orderIndex >= msg.ordersArray.length) {
    node.status({ fill: "yellow", shape: "dot", text: "Usine saturée" });
    delete msg.ordersArray;
    delete msg.orderIndex;
    return null; 
}

let currentOrder = msg.ordersArray[msg.orderIndex];

msg.payload = [currentOrder.order_id];
msg.topic = `
   SELECT
        o.order_id, o.nb_product, pr.*,
        COUNT(p.productSN) AS total_processed,
        SUM(CASE WHEN p.status = 'FINISHED' THEN 1 ELSE 0 END) AS count_finished,
        SUM(CASE WHEN p.status = 'IN_PROGRESS' THEN 1 ELSE 0 END) AS count_in_progress
    FROM Orders o
    JOIN Products pr ON pr.product_type = o.product_type
    LEFT JOIN Production p ON p.order_id = o.order_id AND p.status IN ('FINISHED', 'IN_PROGRESS')
    WHERE o.order_id = ?
    GROUP BY o.order_id;
`;

return msg;

if (!msg.payload || msg.payload.length === 0) {
    node.status({ fill: "red", shape: "ring", text: "Error : No command" });
    return null;
}

let totalProducts = msg.payload[0].nb_product;
let processedProducts = msg.payload[0].total_processed;
let finishedProducts = msg.payload[0].count_finished;

let remainingProducts = totalProducts - processedProducts;
msg.remainingProducts = remainingProducts;

if (remainingProducts > 0) {
    msg.productData = msg.payload[0];
    msg.order_id = msg.payload[0].order_id;
    msg.production_status = "PENDING_PRODUCTS";

    node.status({ fill: "blue", shape: "dot", text: `Remaining ${remainingProducts}/${totalProducts} products (Order ${msg.order_id})` });

    delete msg.ordersArray;
    delete msg.orderIndex;

    return [msg, null, null];

} else if (totalProducts === finishedProducts) {
    msg.production_status = "FINISHED";
    msg.order_id = msg.payload[0].order_id;

    node.status({ fill: "green", shape: "dot", text: `Order ${msg.order_id} Finished !` });

    delete msg.ordersArray;
    delete msg.orderIndex;

    return [null, msg, null];

} else {
    msg.production_status = "NEXT ORDER";

    node.status({ fill: "yellow", shape: "ring", text: "Transition to next order" });

    msg.orderIndex += 1;

    return [null, null, msg];
}

let order_id = msg.order_id;

msg.order_id = order_id;
msg.topic = "UPDATE Orders SET status = 'FINISHED' WHERE order_id = ?;";

msg.payload = [order_id];

return msg;

let machineAnswer = msg.payload; 
let station_number = machineAnswer.station

//let sn = machineAnswer.sn;

let fleet = global.get('factory_fleet');
let priorityType = global.get('production_priority');
let stations = global.get('factory_stations');


if (!fleet || !priorityType) return [msg, null, null]; 

let cart_id = stations[station_number];

// if (cartId !== undefined) {
// } else {
// }

let cart = fleet.find(c => c.cart_id === cart_id);
if (!cart || cart.state === 'IDLE') return [msg, null, null];


if (cart.currentStation === 99 && machineAnswer.response === "CART_IN") { //Adapt Filter to change product while on production

    let currentType = cart.productData.product_type; 
    let order_id = cart.order_id;

    if (currentType !== priorityType) {
        let dbUpdateMsg = {
            topic: "UPDATE Orders SET product_type = ? WHERE order_id = ?;",
            payload: [priorityType, order_id],
            order_id: order_id,
            sn: cart.sn,
            newType: priorityType
        };

        let newAction = "NEW PRIORITY";
        let commandMsg = {
            payload: `[Cart ${cart.cart_id}] OVERRIDE PRIORITY ! Abort previous action. NEW TYPE: ${priorityType} | NEW ACTION: ${newAction}`
        };

        cart.productData.product_type = priorityType;
        global.set('factory_fleet', fleet);

        return [null, dbUpdateMsg, commandMsg];
    }
}

return [msg, null, null];

let sn = msg.sn;
let productData = msg.payload[0];

if (!sn || !productData) return null;

let fleet = global.get('factory_fleet');
if (!fleet) return null;

let cart = fleet.find(c => c.sn === sn);
if (!cart) return null;

productData.order_id = cart.order_id;
cart.productData = productData;

global.set('factory_fleet', fleet);

global.set('factory_fleet', fleet);

return { payload: `[Cart ${cart.cart_id}] Cart Update for product : ${productData.product_type} !` };

let newType = msg.newType;
let sn = msg.sn;
let order_id = msg.order_id;

let dbUpdateMsg = {
            topic: "SELECT o.order_id, o.product_type, p.* FROM Orders o JOIN Products p ON o.product_type = p.product_type JOIN Production pr ON o.order_id = ?;",
            payload: [order_id],
            sn: sn,
            newType: newType
        };

return dbUpdateMsg;

let total_active = msg.payload[0].total_active;

let fleet = global.get('factory_fleet') || [];

let available_carts = fleet.filter(cart => cart.state === 'IDLE');

if (total_active >= 6) {
    node.status({ fill: "red", shape: "ring", text: "Line Full (6/6)" });
    node.warn("Production blocked : 6 products on the line");
    return null;
}

if (available_carts.length === 0) {
    node.status({ fill: "yellow", shape: "ring", text: "No carts available" });
    node.warn("Production blocked : No IDLE carts available");
    return null;
}
msg.topic = "UPDATE Orders SET status = 'IN_PROGRESS' WHERE order_id = ? AND status = 'QUEUED';";
msg.payload = [msg.order_id];

return msg;

msg.topic = `
    SELECT order_id, product_type, nb_product
    FROM Orders
    WHERE status IN ('IN_PROGRESS', 'QUEUED');
`;
return msg;

msg.topic = `
    SELECT o.order_id
    FROM Orders o
    LEFT JOIN Production p ON o.order_id = p.order_id
    WHERE o.priority = TRUE AND o.status IN ('QUEUED', 'IN_PROGRESS')
    GROUP BY o.order_id, o.nb_product
    HAVING COUNT(p.productSN) < o.nb_product
    LIMIT 1;
`;
return msg;

if (msg.payload && msg.payload.length > 0) {
    msg.topic = "UPDATE Orders SET status = 'PAUSED' WHERE priority = FALSE AND status IN ('QUEUED', 'IN_PROGRESS');";

    node.status({fill:"red", shape:"dot", text:"Active Priority"});
} else {
    msg.topic = "UPDATE Orders SET status = 'QUEUED' WHERE priority = FALSE AND status = 'PAUSED';";

    node.status({fill:"green", shape:"dot", text:"No Priority"});
}

return msg;

flow.set("selectedOrderId", msg.payload.order_id);

let msgPriority = { payload: msg.payload.priority === 1 }; 

return msgPriority;

let order_id = flow.get("selectedOrderId");

let newPriority = msg.payload ? 1 : 0;
msg.topic = "UPDATE Orders SET priority = ? WHERE order_id = ?";
msg.payload = [newPriority, order_id];

return msg;

let stations = {};
for (let i = 1; i <= 6; i++) {
    stations["Station" + i] = { active: false };
}

if (Array.isArray(msg.payload)) {
    msg.payload.forEach(row => {
        let stName = row.current_station;
        if (stations[stName]) {
            stations[stName] = {
                active: true,
                sn: row.productSN,
                order: row.order_id,
                cart: row.cart_id,
                op: row[stName + "Op"],
                priority: row.priority
            };
        }
    });
}

msg.payload = stations;
return msg;

let currentDataString = JSON.stringify(msg.payload);

let previousDataString = flow.get("previousTableData");

if (currentDataString === previousDataString) {
    return null;
}

flow.set("previousTableData", currentDataString);

return msg;

let currentIn_PROGRESSString = JSON.stringify(msg.payload);

let previousIN_PROGRESSString = flow.get("previousProgressData");

if (currentIn_PROGRESSString === previousIN_PROGRESSString) {
    return null;
}

flow.set("previousProgressData", currentIn_PROGRESSString);

return msg;

let currentProduction = JSON.stringify(msg.payload);

let previousProduction = flow.get("previousFinishedData");

if (currentProduction === previousProduction) {
    return null;
}

flow.set("previousFinishedData", currentProduction);

return msg;

let sn = msg.payload.productSN;

if (!sn) return null;

msg.productSN = sn;

msg.topic = `
    SELECT 
        pr.*
    FROM Production p
    JOIN Orders o ON p.order_id = o.order_id
    JOIN Products pr ON o.product_type = pr.product_type
    WHERE p.productSN = '${sn}';
`;

return msg;

if (!msg.payload || msg.payload.length === 0) return null;

let recipe = msg.payload[0];
let productionDetails = [];

for (let i = 1; i <= 6; i++) {
    let stop = recipe["Station" + i + "Stop"]; 
    let operation = recipe["Station" + i + "Op"]; 

    productionDetails.push({
        step: "Station " + i,
        required_stop: stop ? "True" : "False",
        action: operation ? operation : "Bypass"
    });
}

msg.payload = productionDetails;

return msg;

if (msg.payload === "connect") {
    flow.set("previousFinishedData", null);
    flow.set("previousProgressData", null);
    flow.set("previousTableData", null);
    flow.set("previousWaitingData", null);
    flow.set("previousFinishedOrdersData", null);
    flow.set("previousTypeProducts", null);
}
return null;

flow.set("selectedWaitingOrderId", msg.payload.order_id);

let msgPriority = { payload: msg.payload.priority === 1 }; 

return msgPriority;

let order_id = flow.get("selectedWaitingOrderId");

msg.topic = "UPDATE Orders SET status = 'QUEUED' WHERE order_id = ?";
msg.payload = [order_id];

return msg;

let currentDataString = JSON.stringify(msg.payload);

let previousDataString = flow.get("previousWaitingData");

if (currentDataString === previousDataString) {
    return null;
}

flow.set("previousWaitingData", currentDataString);

return msg;

let nb_carts = flow.get('nb_carts');

let carts = [];
for (let i = 1; i <= nb_carts; i++) {
    carts.push({
        cart_id: i,
        order_id: null,
        sn: null,
        productData: null,
        currentStation: 0,
        state: 'IDLE'
    });
}

let stations = {
    1: null, 2: null, 3: null, 4: null, 5: null, 6: null
};

global.set('factory_fleet', carts);
global.set('factory_stations', stations);
global.set('production_priority', "A");

return { 
    payload: "Factory Initialized",
    nb_carts: nb_carts
        };

let data = msg.payload;

let s1_op = data.station1_stop ? data.station1_op : null;
let s2_op = data.station2_stop ? data.station2_op : null;
let s3_op = data.station3_stop ? data.station3_op : null;
let s4_op = data.station4_stop ? data.station4_op : null;
let s5_op = data.station5_stop ? data.station5_op : null;
let s6_op = data.station6_stop ? data.station6_op : null;

