    INSERT INTO Products (
        product_type, 
        Station1Stop, Station1Op, 
        Station2Stop, Station2Op, 
        Station3Stop, Station3Op,
        Station4Stop, Station4Op,
        Station5Stop, Station5Op,
        Station6Stop, Station6Op
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
`;

msg.payload = [
    data.product_type, 
    data.station1_stop, s1_op,
    data.station2_stop, s2_op,
    data.station3_stop, s3_op,
    data.station4_stop, s4_op,
    data.station5_stop, s5_op,
    data.station6_stop, s6_op
];

return msg;

let currentProduction = JSON.stringify(msg.payload);

let previousProduction = flow.get("previousFinishedOrdersData");

if (currentProduction === previousProduction) {
    return null;
}

flow.set("previousFinishedOrdersData", currentProduction);

return msg;

let currentIn_PROGRESSString = JSON.stringify(msg.payload);

let previousIN_PROGRESSString = flow.get("previousTypeProducts");

if (currentIn_PROGRESSString === previousIN_PROGRESSString) {
    return null;
}

flow.set("previousTypeProducts", currentIn_PROGRESSString);

return msg;

let formData = msg.payload;

msg.topic = "INSERT INTO Orders (order_id, nb_product, product_type, status) VALUES (1,?, ?, 'WAITING');";

msg.payload = [formData.nb_product, formData.product_type];

return msg;

msg.topic = `
    SELECT o.order_id, o.product_type, p.* FROM Orders o 
    JOIN Products p ON o.product_type = p.product_type 
    WHERE o.status = 'WAITING' 
    LIMIT 1;
`;
return msg;

let data = msg.productData;

let sn = data.order_id; 

msg.numSerie = sn;

msg.topic = "INSERT INTO Production (productSN, order_id, cart_id, current_station, status) VALUES (?, ?, 1, 'Station1', 'IN_PROGRESS');";

msg.payload = [sn, data.order_id];

return msg;

let data = msg.payload[0]; 

msg.productData = data;
msg.topic = "UPDATE Orders SET status = 'IN_PROGRESS' WHERE order_id = ?;";

msg.payload = [data.order_id]; 

return msg;

let data = msg.productData;

let sn = msg.numSerie; 

let stateCart = {
    sn: sn,
    order_id: data.order_id,
    productData: data,
    currentStation: 1,
    state: 'EVALUATION',
    isBypassed: false
};

flow.set('cart_' + sn, stateCart);

msg.payload = { action: 'DECISION', sn: sn };
return msg;

let sn = msg.payload.sn;
let cart = flow.get('cart_' + sn);

if (!cart) return null; 
if (cart.state !== 'EVALUATION') return null;

let numStation = cart.currentStation;

if (numStation > 6) {
    msg.topic = `UPDATE Production SET status = 'FINISHED' WHERE productSN = ${sn};`;
    flow.set('cart_' + sn, undefined);
    return [msg, { payload: `[Product ${sn}] Production finished !` }];
}

let dbUpdateMsg = {
    topic: `UPDATE Production SET current_station = 'Station${numStation}' WHERE productSN = ${sn};`
};

let commandMsg = { payload: {} };
let stopCol = "Station" + numStation + "Stop";
let opCol = "Station" + numStation + "Op";

cart.state = 'ACK_WAIT';

if (cart.productData[stopCol] === 1 || cart.productData[stopCol] === true) {
    cart.isBypassed = false;
    commandMsg.payload = `[Product ${sn} -> Station ${numStation}] INSTRUCTION : ${cart.productData[opCol]}`;
} else {
    cart.isBypassed = true;
    commandMsg.payload = `[Product ${sn} -> Station ${numStation}] CHECK-IN ONLY (Bypass)`;
}

flow.set('cart_' + sn, cart);

return [dbUpdateMsg, commandMsg];

let machineAnswer = msg.payload; 
let sn = machineAnswer.sn;
let cart = flow.get('cart_' + sn);

if (!cart) return null;

if (machineAnswer.response === "ACK" && cart.state === 'ACK_WAIT') {

    if (cart.isBypassed === true) {
        cart.state = 'EVALUATION';
        cart.currentStation++;
        flow.set('cart_' + sn, cart);

        return [
            { payload: `[Product ${sn} -> Station ${cart.currentStation - 1}] ACK received. BYPASSING... MOVE CART !` }, 
            { payload: { action: 'DECISION', sn: sn } } 
        ];
    } else {
        cart.state = 'DONE_WAIT';
        flow.set('cart_' + sn, cart);

        return { payload: `[Product ${sn} -> Station ${cart.currentStation}] ACK received. Operation in progress...` };
    }
}

if (machineAnswer.response === "DONE" && cart.state === 'DONE_WAIT') {
    cart.state = 'EVALUATION';
    cart.currentStation++;
    flow.set('cart_' + sn, cart);

    return [
        { payload: `[Product ${sn} -> Station ${cart.currentStation - 1}] DONE received. MOVE CART !` }, 
        { payload: { action: 'DECISION', sn: sn } }     ];
}

return null;
